urlset:
{{/* 태그 term/목록 페이지는 사이트맵에서 뺀다 — 글보다 얇고 수가 많아(실측: 글
     118개 대비 태그 212개) 구글이 정작 중요한 글에 크롤링 예산을 못 쓰게 만든다.
     카테고리 페이지는 수가 적고(8개) 실제 탐색 허브 역할을 하므로 그대로 둔다. */}}
{{ range .Data.Pages }}
{{ $isTagTaxonomy := false }}
{{ if in (slice "taxonomy" "term") .Kind }}
  {{ if eq .Data.Plural "tags" }}{{ $isTagTaxonomy = true }}{{ end }}
{{ end }}
{{ if not $isTagTaxonomy }}

    {{ .Permalink }}{{ if not .Lastmod.IsZero }}
    {{ safeHTML ( .Lastmod.Format "2006-01-02T15:04:05-07:00" ) }}{{ end }}{{ with .Sitemap.ChangeFreq }}
    {{ . }}{{ end }}{{ if ge .Sitemap.Priority 0.0 }}
    {{ .Sitemap.Priority }}{{ end }}

{{ end }}
{{ end }}
